  ('elementary-64311456-moex-00347', 'elementary-64311456', 'elementary-64311456-moex-113-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '社會工作師法的通過，對於臺灣社會工作的專業化與法制化是重要的一大步。請問社會工作師法最早是在 何年制定與公布？', '["1996", "1997", "1998", "1999"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:08+00:00", "source_pdf_sha1": "5c9616efa256", "answer_pdf_sha1": "58ee787f2e9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "502", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
